import{_ as o,o as a,c,a2 as d}from"./chunks/framework.BKG_UbFK.js";const m=JSON.parse('{"title":"Arquitectura","description":"","frontmatter":{},"headers":[],"relativePath":"es/guide/architecture.md","filePath":"es/guide/architecture.md"}'),t={name:"es/guide/architecture.md"};function r(s,e,i,n,l,u){return a(),c("div",null,[...e[0]||(e[0]=[d('<h1 id="arquitectura" tabindex="-1">Arquitectura <a class="header-anchor" href="#arquitectura" aria-label="Permalink to &quot;Arquitectura&quot;">​</a></h1><h2 id="como-funciona-la-resolucion" tabindex="-1">Cómo funciona la resolución <a class="header-anchor" href="#como-funciona-la-resolucion" aria-label="Permalink to &quot;Cómo funciona la resolución&quot;">​</a></h2><p><code>resolveFor()</code> es el núcleo de la autorización contextual de Clearance - consulta <a href="/clearance-docs/es/features/contextual-authorization.html">Autorización Contextual</a> para la API completa. Combina tres fuentes, en este orden de precedencia:</p><ol><li><strong>Concesiones de rol contextual</strong> - permisos de los roles que el usuario posee específicamente dentro de este contexto (<code>clr_role_ctx</code>).</li><li><strong>Concesiones de rol global</strong> - permisos de los roles Spatie asignados globalmente al usuario (de modo que <code>super_admin</code> y otros roles globales satisfacen <code>canIn()</code> para cualquier contexto).</li><li><strong>Overrides por contexto</strong> (<code>clr_ctx_overrides</code>) - <code>forced_on</code> añade un permiso encima de lo anterior; <code>forced_off</code> lo elimina, incluso si el permiso fue concedido por un rol global. Una denegación siempre gana.</li></ol><div class="warning custom-block"><p class="custom-block-title">Una denegación siempre gana</p><p><code>forced_off</code> anula cualquier permiso concedido por un rol global o una concesión de rol contextual. No hay forma de &quot;superar en rango&quot; a un override <code>forced_off</code> para el mismo usuario/permiso/contexto, salvo eliminándolo.</p></div><h2 id="base-de-datos" tabindex="-1">Base de datos <a class="header-anchor" href="#base-de-datos" aria-label="Permalink to &quot;Base de datos&quot;">​</a></h2><p>Clearance posee 6 tablas y nunca altera las tablas núcleo de Spatie (<code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code>, <code>role_has_permissions</code>). Todas las FK que referencian <code>roles.id</code>/<code>permissions.id</code> hacen cascade on delete salvo que se indique lo contrario; las tablas de Spatie no tienen FKs que apunten de vuelta a <code>clr_*</code>.</p><table tabindex="0"><thead><tr><th>Tabla</th><th>Columnas clave</th></tr></thead><tbody><tr><td><code>clr_meta</code></td><td><code>subject_type</code>, <code>subject_key</code> (únicos en conjunto) - <code>display_name</code>, <code>description</code>, <code>icon_svg</code>, <code>color</code> - metadatos de visualización para un rol o guard</td></tr><tr><td><code>clr_role_meta</code></td><td><code>role_id</code> (único, FK -&gt; <code>roles</code>) - <code>is_locked</code>, <code>scope</code> (<code>global</code>|<code>contextual</code>), <code>context_types</code> (json) - <code>parent_role_id</code> (FK anulable -&gt; <code>roles</code>, <code>ON DELETE SET NULL</code>) - rol techo</td></tr><tr><td><code>clr_guards</code></td><td><code>name</code> (único), <code>driver</code>, <code>provider</code> - guards gestionados vía el panel</td></tr><tr><td><code>clr_settings</code></td><td><code>key</code> (único), <code>value</code> - almacén clave/valor en tiempo de ejecución (rol predeterminado, etc.)</td></tr><tr><td><code>clr_role_ctx</code></td><td><code>user_id</code>, <code>role_id</code> (FK -&gt; <code>roles</code>), <code>context_type</code>, <code>context_id</code> - asignaciones de rol contextual, únicas por <code>(user, role, context_type, context_id)</code></td></tr><tr><td><code>clr_ctx_overrides</code></td><td><code>user_id</code>, <code>role_id</code> (FK -&gt; <code>roles</code>), <code>permission_id</code> (FK -&gt; <code>permissions</code>), <code>context_type</code>, <code>context_id</code>, <code>type</code> (<code>forced_on</code>|<code>forced_off</code>) - overrides de permiso por usuario y por contexto</td></tr></tbody></table><h2 id="nunca-toca-las-tablas-de-spatie" tabindex="-1">Nunca toca las tablas de Spatie <a class="header-anchor" href="#nunca-toca-las-tablas-de-spatie" aria-label="Permalink to &quot;Nunca toca las tablas de Spatie&quot;">​</a></h2><p>Clearance está diseñado para convivir junto a <code>spatie/laravel-permission</code>, no para reemplazarlo. Cada registro <code>Role</code> y <code>Permission</code> que un panel de Clearance crea o edita es un modelo Spatie genuino, almacenado en las propias tablas de Spatie. Clearance nunca ejecuta una migración que añada una columna a, o escriba una FK desde, ninguna de <code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code>, o <code>role_has_permissions</code>.</p><p>Todos los datos propios de Clearance - metadatos de visualización, alcance y techos de rol, asignaciones contextuales, overrides por contexto, definiciones de guard, y configuración - viven exclusivamente en las 6 tablas <code>clr_*</code> anteriores. Esto significa que:</p><ul><li>Desinstalar Clearance nunca arriesga corromper tus datos existentes de rol/permiso de Spatie.</li><li>Cualquier código que ya lea los modelos o tablas de Spatie directamente sigue funcionando sin modificaciones.</li><li>Las funciones contextuales y de techo de Clearance son capas puramente aditivas resueltas en tiempo de consulta (vía <code>resolveFor()</code> y <code>RoleService</code>), no incorporadas al esquema de Spatie.</li></ul><h2 id="relacionado" tabindex="-1">Relacionado <a class="header-anchor" href="#relacionado" aria-label="Permalink to &quot;Relacionado&quot;">​</a></h2><ul><li><a href="/clearance-docs/es/features/contextual-authorization.html">Autorización Contextual</a> - <code>canIn()</code>, <code>hasRoleIn()</code>, directivas Blade, <code>ContextService</code></li><li><a href="/clearance-docs/es/features/roles.html">Roles</a> - alcance y roles techo, <code>RoleService::setParent()</code></li><li><a href="/clearance-docs/es/guide/migration.html">Migración</a> - rellenar <code>clr_meta</code>/<code>clr_role_meta</code>/<code>clr_guards</code> sobre una instalación de Spatie existente</li><li><a href="/clearance-docs/es/guide/security.html">Seguridad</a> - cómo el modelo de techo y override previene la escalada de privilegios</li></ul>',14)])])}const _=o(t,[["render",r]]);export{m as __pageData,_ as default};
